CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_generar_data_masiva_oltp` ()   BEGIN
    -- ¡AQUÍ ESTÁ LA SOLUCIÓN! Empezamos a contar desde el 100 para evitar duplicados
    DECLARE i INT DEFAULT 100; 
    DECLARE v_persona_id BIGINT;
    DECLARE v_matricula_id BIGINT;
    DECLARE v_dni VARCHAR(20);
    DECLARE v_cod VARCHAR(50);

    -- Bucle para crear los estudiantes (llegará hasta el 2600)
    WHILE i <= 2600 DO
        -- Generar DNI y Código únicos rellenando con ceros
        SET v_dni = LPAD(i, 8, '0');
        SET v_cod = CONCAT('EST-', LPAD(i, 5, '0'));

        -- Insertar en tabla Personas
        VALUES (v_dni, CONCAT('Alumno_Generado_', i), 'Simulación', '2010-05-15');
        
        SET v_persona_id = LAST_INSERT_ID();

        -- Insertar en tabla Estudiantes
        VALUES (v_persona_id, v_cod, '2026-03-01');

        -- Matricular al estudiante
        VALUES (LAST_INSERT_ID(), 1, 1, '2026-03-05', 'REGULAR');
        
        SET v_matricula_id = LAST_INSERT_ID();

        -- Insertar 6 notas aleatorias por estudiante

        SET i = i + 1;
    END WHILE;
END$$

